import pytest

from your_module import retry


def test_retry_returns_on_first_success():
    def fn():
        return "ok"

    assert retry(fn) == "ok"


def test_retry_retries_until_success():
    calls = {"count": 0}

    def fn():
        calls["count"] += 1
        if calls["count"] < 3:
            raise ValueError("temporary failure")
        return "done"

    result = retry(fn, max_attempts=3)

    assert result == "done"
    assert calls["count"] == 3


def test_retry_raises_last_exception_after_max_attempts():
    calls = {"count": 0}

    def fn():
        calls["count"] += 1
        raise RuntimeError("always fails")

    with pytest.raises(RuntimeError, match="always fails"):
        retry(fn, max_attempts=3)

    assert calls["count"] == 3


def test_retry_with_one_attempt_calls_once_and_raises():
    calls = {"count": 0}

    def fn():
        calls["count"] += 1
        raise ValueError("fail")

    with pytest.raises(ValueError, match="fail"):
        retry(fn, max_attempts=1)

    assert calls["count"] == 1


def test_retry_with_zero_attempts_returns_none_without_calling():
    calls = {"count": 0}

    def fn():
        calls["count"] += 1
        return "should not be called"

    result = retry(fn, max_attempts=0)

    assert result is None
    assert calls["count"] == 0


def test_retry_with_negative_attempts_returns_none_without_calling():
